-- Acts 25 — Paul Before Festus: The Appeal to Caesar
-- Theme: "Caesarem Appello" — The Gospel Routed to Rome

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 25,
  'Acts 25 turns on a single word — "I appeal unto Caesar" — that sets Paul irrevocably on the road to Rome. The new governor Porcius Festus, only three days in the province, goes up from Caesarea to Jerusalem, where the chief priests and leading Jews immediately press him to transfer Paul for trial at Jerusalem, planning another ambush on the road. Festus refuses the venue change but invites them down to Caesarea. After ten days he convenes court; the Jews lay many grievous complaints they cannot prove. Paul answers with the same defence as before: "Neither against the law of the Jews, neither against the temple, nor yet against Caesar, have I offended any thing at all." Festus, willing to do the Jews a pleasure, asks whether Paul will go up to Jerusalem for trial. Paul, perceiving the trap and exhausted by two years of delay, uses his Roman citizen''s right: "Caesarem appello." Festus, after conference with his council, answers, "Unto Caesar thou hast appealed? unto Caesar shalt thou go." Shortly thereafter King Agrippa II and his sister Bernice visit to salute the new governor. Festus, stumped for what to write to the emperor about a prisoner whose case is mere Jewish theological dispute, lays the matter before Agrippa, who wishes to hear the man himself. The next day, in great pomp, Agrippa and Bernice enter the audience hall and Paul is brought in — a prisoner to supply a charge for his own letter of transfer.',
  '"Caesarem Appello" — The Gospel Routed to Rome',
  'ἐπικαλοῦμαι',
  'I appeal, invoke (epikaloumai) — Paul''s formal appeal to the emperor in v.11, claiming his right as a Roman citizen.',
  '[{"range":"vv.1-5","title":"Festus in Jerusalem: The Second Ambush Plan"},{"range":"vv.6-8","title":"The Hearing at Caesarea"},{"range":"vv.9-12","title":"The Appeal to Caesar"},{"range":"vv.13-22","title":"Agrippa and Bernice; Festus'' Dilemma"},{"range":"vv.23-27","title":"The Grand Audience and the Missing Charge"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now when Festus was come into the province, after three days he ascended from Caesarea to Jerusalem.',
      'Φῆστος οὖν ἐπιβὰς τῇ ἐπαρχίᾳ, μετὰ τρεῖς ἡμέρας ἀνέβη εἰς Ἱεροσόλυμα ἀπὸ Καισαρείας.',
      'Phēstos oun epibas tē eparchia, meta treis hēmeras anebē eis Hierosolyma apo Kaisareias.',
      'Porcius Festus arrived c. AD 59. His three-day delay before going up to Jerusalem demonstrates proper procedural urgency — the new governor introduces himself to the ecclesiastical power-brokers.',
      'New authorities face old troubles. Every fresh administration inherits unsettled cases against the servants of Christ.'),
  (2, 'Then the high priest and the chief of the Jews informed him against Paul, and besought him,',
      'ἐνεφάνισαν δὲ αὐτῷ ὁ ἀρχιερεὺς καὶ οἱ πρῶτοι τῶν Ἰουδαίων κατὰ τοῦ Παύλου, καὶ παρεκάλουν αὐτόν,',
      'enephanisan de autō ho archiereus kai hoi prōtoi tōn Ioudaiōn kata tou Paulou, kai parekaloun auton,',
      'Ananias''s successor Ishmael son of Phabi is likely the high priest by AD 59. Two years have not cooled Jewish hostility; the case is their first priority with the new procurator.',
      'The servant of Christ who has been forgotten by the world is still remembered by his enemies. Gospel hatred has a long memory.'),
  (3, 'And desired favour against him, that he would send for him to Jerusalem, laying wait in the way to kill him.',
      'αἰτούμενοι χάριν κατ᾽ αὐτοῦ, ὅπως μεταπέμψηται αὐτὸν εἰς Ἱερουσαλήμ, ἐνέδραν ποιοῦντες ἀνελεῖν αὐτὸν κατὰ τὴν ὁδόν.',
      'aitoumenoi charin kat autou, hopōs metapempsētai auton eis Ierousalēm, enedran poiountes anelein auton kata tēn hodon.',
      'A repeat of the forty-man plot (23:12-15), on a larger scale. Had Festus granted the venue change, Paul would not have survived the journey.',
      'The same plot returns in new costume. Evil does not easily abandon its purpose and will try every fresh opportunity.'),
  (4, 'But Festus answered, that Paul should be kept at Caesarea, and that he himself would depart shortly thither.',
      'Ὁ μὲν οὖν Φῆστος ἀπεκρίθη, τηρεῖσθαι τὸν Παῦλον ἐν Καισαρείᾳ, ἑαυτὸν δὲ μέλλειν ἐν τάχει ἐκπορεύεσθαι.',
      'Ho men oun Phēstos apekrithē, tēreisthai ton Paulon en Kaisareia, heauton de mellein en tachei ekporeuesthai.',
      'Festus correctly insists on Caesarea as the venue — the provincial capital, where governors ordinarily heard major cases.',
      'The Lord uses proper legal procedure itself as a bulwark against violence. Roman administrative protocol proves divine providence.'),
  (5, 'Let them therefore, said he, which among you are able, go down with me, and accuse this man, if there be any wickedness in him.',
      'Οἱ οὖν δυνατοὶ ἐν ὑμῖν, φησί, συγκαταβάντες, εἴ τί ἐστιν ἄτοπον ἐν τῷ ἀνδρί, κατηγορείτωσαν αὐτοῦ.',
      'Hoi oun dynatoi en hymin, phēsi, synkatabantes, ei ti estin atopon en tō andri, katēgoreitōsan autou.',
      'Atopon — literally "out of place," i.e. any criminal misconduct. Festus summons the able men down to face their prisoner under Roman law.',
      'Truth is unafraid of proper venue. The gospel welcomes the formal hearing that slander dreads.'),
  (6, 'And when he had tarried among them more than ten days, he went down unto Caesarea; and the next day sitting on the judgment seat commanded Paul to be brought.',
      'Διατρίψας δὲ ἐν αὐτοῖς ἡμέρας πλείους ἢ δέκα, καταβὰς εἰς Καισάρειαν, τῇ ἐπαύριον καθίσας ἐπὶ τοῦ βήματος ἐκέλευσε τὸν Παῦλον ἀχθῆναι.',
      'Diatripsas de en autois hēmeras pleious ē deka, katabas eis Kaisareian, tē epaurion kathisas epi tou bēmatos ekeleuse ton Paulon achthēnai.',
      'The bēma was the elevated tribunal platform from which Roman governors pronounced judgment. Archaeological remains of bēmata survive at Corinth, Caesarea, and elsewhere.',
      'God stages His servants before elevated tribunals only to exalt the gospel higher. The bench of the judge becomes a pulpit for the accused.'),
  (7, 'And when he was come, the Jews which came down from Jerusalem stood round about, and laid many and grievous complaints against Paul, which they could not prove.',
      'Παραγενομένου δὲ αὐτοῦ, περιέστησαν οἱ ἀπὸ Ἱεροσολύμων καταβεβηκότες Ἰουδαῖοι, πολλὰ καὶ βαρέα αἰτιώματα φέροντες κατὰ τοῦ Παύλου, ἃ οὐκ ἴσχυον ἀποδεῖξαι·',
      'Paragenomenou de autou, periestēsan hoi apo Hierosolymōn katabebēkotes Ioudaioi, polla kai barea aitiōmata pherontes kata tou Paulou, ha ouk ischyon apodeixai;',
      'Aitiōmata — "grievous charges." Apodeixai — "prove." Luke highlights again (as in 24:13) the total failure to substantiate the accusations.',
      'A sum of unproven charges is still zero. Weight of allegation, without weight of evidence, proves nothing at the judgment bar.'),
  (8, 'While he answered for himself, Neither against the law of the Jews, neither against the temple, nor yet against Caesar, have I offended any thing at all.',
      'ἀπολογουμένου αὐτοῦ, ὅτι Οὔτε εἰς τὸν νόμον τῶν Ἰουδαίων, οὔτε εἰς τὸ ἱερόν, οὔτε εἰς Καίσαρά τι ἥμαρτον.',
      'apologoumenou autou, hoti Oute eis ton nomon tōn Ioudaiōn, oute eis to hieron, oute eis Kaisara ti hēmarton.',
      'Paul''s tri-fold denial exactly parallels the tri-fold charge (law, temple, and now Caesar — implying they accused him of sedition). Compact and comprehensive.',
      'The Christian has no quarrel with God''s law, God''s house, or Caesar''s lawful rule. Gospel liberty is deeply orderly.'),
  (9, 'But Festus, willing to do the Jews a pleasure, answered Paul, and said, Wilt thou go up to Jerusalem, and there be judged of these things before me?',
      'Ὁ Φῆστος δὲ τοῖς Ἰουδαίοις θέλων χάριν καταθέσθαι, ἀποκριθεὶς τῷ Παύλῳ εἶπε, Θέλεις εἰς Ἱεροσόλυμα ἀναβάς, ἐκεῖ περὶ τούτων κρίνεσθαι ἐπ᾽ ἐμοῦ;',
      'Ho Phēstos de tois Ioudaiois thelōn charin katathesthai, apokritheis tō Paulō eipe, Theleis eis Hierosolyma anabas, ekei peri toutōn krinesthai ep emou?',
      'The new governor, wanting to start well with the Jewish leadership, offers a dangerous compromise. "Before me" still — but in Jerusalem, with Sanhedrin jurors.',
      'Good intentions and political convenience together can wound the innocent. Compromise with influence is the most tempting injustice of new authorities.'),
  (10, 'Then said Paul, I stand at Caesar''s judgment seat, where I ought to be judged: to the Jews have I done no wrong, as thou very well knowest.',
      'Εἶπε δὲ ὁ Παῦλος, Ἐπὶ τοῦ βήματος Καίσαρος ἑστώς εἰμι, οὗ με δεῖ κρίνεσθαι· Ἰουδαίους οὐδὲν ἠδίκησα, ὡς καὶ σὺ κάλλιον ἐπιγινώσκεις.',
      'Eipe de ho Paulos, Epi tou bēmatos Kaisaros hestōs eimi, hou me dei krinesthai; Ioudaious ouden ēdikēsa, hōs kai sy kallion epiginōskeis.',
      'The Roman provincial bench was the emperor''s bench by delegation. Paul asserts his citizen''s right: I am already standing at Caesar''s tribunal; why send me elsewhere? "Thou knowest" is a gentle jab — Festus knows the case has no merit.',
      'Rights given by providence may be claimed without sin. The apostle insists on proper venue as a gift from the same God who ordained the state.'),
  (11, 'For if I be an offender, or have committed any thing worthy of death, I refuse not to die: but if there be none of these things whereof these accuse me, no man may deliver me unto them. I appeal unto Caesar.',
      'εἰ μὲν γὰρ ἀδικῶ, καὶ ἄξιον θανάτου πέπραχά τι, οὐ παραιτοῦμαι τὸ ἀποθανεῖν· εἰ δὲ οὐδέν ἐστιν ὧν οὗτοι κατηγοροῦσί μου, οὐδείς με δύναται αὐτοῖς χαρίσασθαι. Καίσαρα ἐπικαλοῦμαι.',
      'ei men gar adikō, kai axion thanatou pepracha ti, ou paraitoumai to apothanein; ei de ouden estin hōn houtoi katēgorousi mou, oudeis me dynatai autois charisasthai. Kaisara epikaloumai.',
      'Caesarem appello — the Roman citizen''s right of provocatio to the emperor''s personal court. The sitting emperor was Nero (AD 54-68, still in his quinquennium bonum). Charisasthai — "give as a favour" — Paul warns against becoming a political gift.',
      'God''s servants do not shrink from death when justice demands it, but they do resist injustice when law allows. The apostle''s appeal is neither cowardice nor escape, but faith in lawful means.'),
  (12, 'Then Festus, when he had conferred with the council, answered, Hast thou appealed unto Caesar? unto Caesar shalt thou go.',
      'Τότε ὁ Φῆστος συλλαλήσας μετὰ τοῦ συμβουλίου ἀπεκρίθη, Καίσαρα ἐπικέκλησαι; ἐπὶ Καίσαρα πορεύσῃ.',
      'Tote ho Phēstos syllalēsas meta tou symbouliou apekrithē, Kaisara epikeklēsai? epi Kaisara poreusē.',
      'The symboulion was the governor''s advisory council. Once the appeal was lodged and accepted, the case passed to imperial jurisdiction — Festus could no longer release Paul (cf. 26:32).',
      'One word, rightly spoken, can settle a life''s itinerary. "Unto Caesar shalt thou go" — and the Lord''s "thou must also bear witness at Rome" (23:11) advances toward fulfilment.'),
  (13, 'And after certain days king Agrippa and Bernice came unto Caesarea to salute Festus.',
      'Ἡμερῶν δὲ διαγενομένων τινῶν, Ἀγρίππας ὁ βασιλεὺς καὶ Βερνίκη κατήντησαν εἰς Καισάρειαν, ἀσπασόμενοι τὸν Φῆστον.',
      'Hēmerōn de diagenomenōn tinōn, Agrippas ho basileus kai Bernikē katēntēsan eis Kaisareian, aspasomenoi ton Phēston.',
      'Herod Agrippa II (son of the Agrippa I of Acts 12) ruled Chalcis, then various regions of northeastern Palestine under Nero. Bernice was his sister, with whom he lived in rumoured incest (Josephus, Ant. 20.7.3; Juvenal, Sat. 6.155-159). She later became mistress of the future emperor Titus.',
      'God brings His gospel to the very inner circle of Herodian royalty. Before Christ came the son of Herod plotted His death; now another son of Herod hears His servant.'),
  (14, 'And when they had been there many days, Festus declared Paul''s cause unto the king, saying, There is a certain man left in bonds by Felix:',
      'Ὡς δὲ πλείους ἡμέρας διέτριβον ἐκεῖ, ὁ Φῆστος τῷ βασιλεῖ ἀνέθετο τὰ κατὰ τὸν Παῦλον, λέγων, Ἀνήρ τίς ἐστι καταλελειμμένος ὑπὸ Φήλικος δέσμιος,',
      'Hōs de pleious hēmeras dietribon ekei, ho Phēstos tō basilei anetheto ta kata ton Paulon, legōn, Anēr tis esti kataleleimmenos hypo Phēlikos desmios,',
      'Anetheto ("set before, conferred with") — Festus formally consults Agrippa, who as client-king had specialised knowledge of Jewish religious matters.',
      'God''s counsel manoeuvres governors into sharing the gospel''s story at leisure. Every dinner conversation about Paul spreads the name of Christ further.'),
  (15, 'About whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, desiring to have judgment against him.',
      'περὶ οὗ, γενομένου μου εἰς Ἱεροσόλυμα, ἐνεφάνισαν οἱ ἀρχιερεῖς καὶ οἱ πρεσβύτεροι τῶν Ἰουδαίων, αἰτούμενοι κατ᾽ αὐτοῦ δίκην.',
      'peri hou, genomenou mou eis Hierosolyma, enephanisan hoi archiereis kai hoi presbyteroi tōn Ioudaiōn, aitoumenoi kat autou dikēn.',
      'Dikēn here = condemnation/sentence. The priests asked for a verdict, not a fair trial.',
      'Religious institutions that press civil magistrates for pre-formed verdicts have already forsaken justice. Conscience cannot ask for judgment — only for law.'),
  (16, 'To whom I answered, It is not the manner of the Romans to deliver any man to die, before that he which is accused have the accusers face to face, and have licence to answer for himself concerning the crime laid against him.',
      'πρὸς οὓς ἀπεκρίθην, ὅτι οὐκ ἔστιν ἔθος Ῥωμαίοις χαρίζεσθαί τινα ἄνθρωπον εἰς ἀπώλειαν, πρὶν ἢ ὁ κατηγορούμενος κατὰ πρόσωπον ἔχοι τοὺς κατηγόρους, τόπον τε ἀπολογίας λάβοι περὶ τοῦ ἐγκλήματος.',
      'pros hous apekrithēn, hoti ouk estin ethos Rhōmaiois charizesthai tina anthrōpon eis apōleian, prin ē ho katēgoroumenos kata prosōpon echoi tous katēgorous, topon te apologias laboi peri tou enklēmatos.',
      'A classic statement of Roman judicial fairness — accusers must face the accused, and the accused has opportunity for defence. Codified later in Justinian (Digest 48.17).',
      'Even pagan Rome enshrined principles of due process that Christian jurisprudence would inherit. God plants seeds of justice in unbelieving soil.'),
  (17, 'Therefore, when they were come hither, without any delay on the morrow I sat on the judgment seat, and commanded the man to be brought forth.',
      'Συνελθόντων οὖν αὐτῶν ἐνθάδε, ἀναβολὴν μηδεμίαν ποιησάμενος, τῇ ἑξῆς καθίσας ἐπὶ τοῦ βήματος ἐκέλευσα ἀχθῆναι τὸν ἄνδρα·',
      'Synelthontōn oun autōn enthade, anabolēn mēdemian poiēsamenos, tē hexēs kathisas epi tou bēmatos ekeleusa achthēnai ton andra;',
      'Festus stresses his own procedural diligence. The contrast with Felix''s two-year delay is underlined.',
      'Administrative virtue answers past corruption. Speedy hearings are mercies; drawn-out delays often disguise contempt.'),
  (18, 'Against whom when the accusers stood up, they brought none accusation of such things as I supposed:',
      'περὶ οὗ σταθέντες οἱ κατήγοροι οὐδεμίαν αἰτίαν ἐπέφερον ὧν ὑπενόουν ἐγώ·',
      'peri hou stathentes hoi katēgoroi oudemian aitian epepheron hōn hypenooun egō;',
      'Festus had expected criminal charges — he got only theological disputation. Strong testimony to the apostolic faith''s legal innocence.',
      'Romans who investigated Christianity found it legally blameless. The slander of sedition evaporates before sober inquiry.'),
  (19, 'But had certain questions against him of their own superstition, and of one Jesus, which was dead, whom Paul affirmed to be alive.',
      'ζητήματα δέ τινα περὶ τῆς ἰδίας δεισιδαιμονίας εἶχον πρὸς αὐτόν, καὶ περί τινος Ἰησοῦ τεθνηκότος, ὃν ἔφασκεν ὁ Παῦλος ζῆν.',
      'zētēmata de tina peri tēs idias deisidaimonias eichon pros auton, kai peri tinos Iēsou tethnēkotos, hon ephasken ho Paulos zēn.',
      'Deisidaimonia ("superstition" or "religion," neutral or slightly pejorative). Festus reduces the Christian faith to a squabble "about one Jesus... whom Paul affirmed to be alive." A governor''s dismissive summary — yet the living Jesus is indeed the heart of Paul''s gospel.',
      'Pagan officialdom can describe the resurrection with uncomprehending brevity. The living Jesus is the whole of the Christian message, stated plainly even by the unconverted.'),
  (20, 'And because I doubted of such manner of questions, I asked him whether he would go to Jerusalem, and there be judged of these matters.',
      'ἀπορούμενος δὲ ἐγὼ εἰς τὴν περὶ τούτου ζήτησιν, ἔλεγον εἰ βούλοιτο πορεύεσθαι εἰς Ἱερουσαλήμ, κἀκεῖ κρίνεσθαι περὶ τούτων.',
      'aporoumenos de egō eis tēn peri toutou zētēsin, elegon ei bouloito poreuesthai eis Ierousalēm, kakei krinesthai peri toutōn.',
      'Festus sanitises his own earlier offer — his compromise is now framed as judicial perplexity rather than Jewish favour.',
      'Officials airbrush their own embarrassments when speaking up the chain. God sees every stroke of the retouch.'),
  (21, 'But when Paul had appealed to be reserved unto the hearing of Augustus, I commanded him to be kept till I might send him to Caesar.',
      'τοῦ δὲ Παύλου ἐπικαλεσαμένου τηρηθῆναι αὐτὸν εἰς τὴν τοῦ Σεβαστοῦ διάγνωσιν, ἐκέλευσα τηρεῖσθαι αὐτόν, ἕως οὗ πέμψω αὐτὸν πρὸς Καίσαρα.',
      'tou de Paulou epikalesamenou tērēthēnai auton eis tēn tou Sebastou diagnōsin, ekeleusa tēreisthai auton, heōs hou pempsō auton pros Kaisara.',
      '"Augustus" (Sebastos, "venerable one") here is the imperial title, used of Nero. Diagnōsis — formal judicial determination.',
      'Nero himself will be made to hear of Jesus. The emperor''s court becomes a station on the gospel road.'),
  (22, 'Then Agrippa said unto Festus, I would also hear the man myself. To morrow, said he, thou shalt hear him.',
      'Ἀγρίππας δὲ πρὸς τὸν Φῆστον ἔφη, Ἐβουλόμην καὶ αὐτὸς τοῦ ἀνθρώπου ἀκοῦσαι. Ὁ δέ, Αὔριον, φησίν, ἀκούσῃ αὐτοῦ.',
      'Agrippas de pros ton Phēston ephē, Eboulomēn kai autos tou anthrōpou akousai. Ho de, Aurion, phēsin, akousē autou.',
      'Agrippa''s curiosity is providential. A courtroom will convene with no legal outcome — and the highest sermon of Paul''s trials will result.',
      'God stages hearings not for verdicts but for proclamation. Every opportunity to hear Christ is itself the judgement seat of the hearer.'),
  (23, 'And on the morrow, when Agrippa was come, and Bernice, with great pomp, and was entered into the place of hearing, with the chief captains, and principal men of the city, at Festus'' commandment Paul was brought forth.',
      'Τῇ οὖν ἐπαύριον, ἐλθόντος τοῦ Ἀγρίππα καὶ τῆς Βερνίκης μετὰ πολλῆς φαντασίας, καὶ εἰσελθόντων εἰς τὸ ἀκροατήριον, σύν τε τοῖς χιλιάρχοις καὶ ἀνδράσι τοῖς κατ᾽ ἐξοχὴν οὖσι τῆς πόλεως, καὶ κελεύσαντος τοῦ Φήστου, ἤχθη ὁ Παῦλος.',
      'Tē oun epaurion, elthontos tou Agrippa kai tēs Bernikēs meta pollēs phantasias, kai eiselthontōn eis to akroatērion, syn te tois chiliarchois kai andrasi tois kat exochēn ousi tēs polis, kai keleusantos tou Phēstou, ēchthē ho Paulos.',
      'Phantasia — "pomp, ostentation." Akroatērion — "audience hall." Five tribunes (each commanding 1000 men) were garrisoned at Caesarea. All Caesarea''s elite are present.',
      'The chained apostle confronts the theatre of earthly power. The gospel enters the hall of pomp carrying only chains and a testimony.'),
  (24, 'And Festus said, King Agrippa, and all men which are here present with us, ye see this man, about whom all the multitude of the Jews have dealt with me, both at Jerusalem, and also here, crying that he ought not to live any longer.',
      'καί φησιν ὁ Φῆστος, Ἀγρίππα βασιλεῦ, καὶ πάντες οἱ συμπαρόντες ἡμῖν ἄνδρες, θεωρεῖτε τοῦτον περὶ οὗ πᾶν τὸ πλῆθος τῶν Ἰουδαίων ἐνέτυχόν μοι ἔν τε Ἱεροσολύμοις καὶ ἐνθάδε, ἐπιβοῶντες μὴ δεῖν ζῇν αὐτὸν μηκέτι.',
      'kai phēsin ho Phēstos, Agrippa basileu, kai pantes hoi symparontes hēmin andres, theōreite touton peri hou pan to plēthos tōn Ioudaiōn enetychon moi en te Hierosolymois kai enthade, epiboōntes mē dein zēn auton mēketi.',
      'Festus acknowledges the universal Jewish animosity without agreeing with it.',
      'The world can be unanimous in its hostility and still wrong. Loudness is not truth.'),
  (25, 'But when I found that he had committed nothing worthy of death, and that he himself hath appealed to Augustus, I have determined to send him.',
      'ἐγὼ δὲ καταλαβόμενος μηδὲν ἄξιον θανάτου αὐτὸν πεπραχέναι, καὶ αὐτοῦ δὲ τούτου ἐπικαλεσαμένου τὸν Σεβαστόν, ἔκρινα πέμπειν αὐτόν.',
      'egō de katalabomenos mēden axion thanatou auton peprachenai, kai autou de toutou epikalesamenou ton Sebaston, ekrina pempein auton.',
      'Festus publicly acknowledges Paul''s legal innocence — another Roman verdict of "nothing worthy of death" (cf. Luke 23:4, 14-15, 22).',
      'Five Roman officials (Lysias, Felix, Festus, Agrippa, the centurion at the cross) witness to the innocence of Jesus and His apostle. Rome''s own records attest the injustice.'),
  (26, 'Of whom I have no certain thing to write unto my lord. Wherefore I have brought him forth before you, and specially before thee, O king Agrippa, that, after examination had, I might have somewhat to write.',
      'περὶ οὗ ἀσφαλές τι γράψαι τῷ Κυρίῳ οὐκ ἔχω. διὸ προήγαγον αὐτὸν ἐφ᾽ ὑμῶν, καὶ μάλιστα ἐπὶ σοῦ, βασιλεῦ Ἀγρίππα, ὅπως τῆς ἀνακρίσεως γενομένης σχῶ τι γράψαι.',
      'peri hou asphales ti grapsai tō Kyriō ouk echō. dio proēgagon auton eph hymōn, kai malista epi sou, basileu Agrippa, hopōs tēs anakriseōs genomenēs schō ti grapsai.',
      '"My lord" (tō Kyriō) is now applied to Nero — the imperial title Christians will refuse to render. A transfer letter required a precise legal cause (elogium); Festus has none.',
      'Even the title "Lord" is contested ground. To call Nero "kyrios" is the next generation''s cost of discipleship.'),
  (27, 'For it seemeth to me unreasonable to send a prisoner, and not withal to signify the crimes laid against him.',
      'ἄλογον γάρ μοι δοκεῖ, πέμποντα δέσμιον, μὴ καὶ τὰς κατ᾽ αὐτοῦ αἰτίας σημᾶναι.',
      'alogon gar moi dokei, pemponta desmion, mē kai tas kat autou aitias sēmanai.',
      'Alogon — "irrational, absurd." Festus openly admits he cannot formulate a legal charge against Paul — yet he has confirmed his appeal. A remarkable own-goal.',
      'The world''s verdict on the gospel is often self-refuting. The governor who sends the apostle to Rome cannot say why.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 25
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐπαρχίᾳ', 'eparchia', 'G1885', 'Province — Roman administrative division.', 1),
  (3, 'ἐνέδραν', 'enedran', 'G1747', 'Ambush — the renewed Jewish plot against Paul''s life.', 2),
  (5, 'ἄτοπον', 'atopon', 'G824', 'Out of place, criminal — used of any unlawful deed.', 3),
  (6, 'βήματος', 'bēmatos', 'G968', 'Bēma — elevated judgment platform.', 4),
  (7, 'αἰτιώματα', 'aitiōmata', 'G157', 'Grievous charges — formal accusations.', 5),
  (7, 'ἀποδεῖξαι', 'apodeixai', 'G584', 'To prove, demonstrate — legal burden of proof.', 6),
  (9, 'χάριν καταθέσθαι', 'charin katathesthai', 'G5485/G2698', 'To lay up favour — political back-scratching.', 7),
  (10, 'Καίσαρος', 'Kaisaros', 'G2541', 'Caesar — the imperial ruler, here Nero.', 8),
  (11, 'παραιτοῦμαι', 'paraitoumai', 'G3868', 'I beg off, refuse — Paul does not refuse just execution.', 9),
  (11, 'χαρίσασθαι', 'charisasthai', 'G5483', 'To give as favour — political gift.', 10),
  (11, 'ἐπικαλοῦμαι', 'epikaloumai', 'G1941', 'I appeal, invoke — the formal provocatio ad Caesarem.', 11),
  (12, 'συμβουλίου', 'symbouliou', 'G4824', 'Council — governor''s advisory board.', 12),
  (13, 'Ἀγρίππας', 'Agrippas', 'G67', 'Agrippa II — son of Acts 12:1 Agrippa.', 13),
  (13, 'Βερνίκη', 'Bernikē', 'G959', 'Bernice — Agrippa''s sister (later mistress of Titus).', 14),
  (14, 'ἀνέθετο', 'anetheto', 'G394', 'Set before, conferred with — formal consultation.', 15),
  (15, 'δίκην', 'dikēn', 'G1349', 'Sentence, condemnation — not just trial but verdict.', 16),
  (16, 'κατὰ πρόσωπον', 'kata prosōpon', 'G4383', 'Face to face — the confrontation clause of Roman law.', 17),
  (16, 'τόπον ἀπολογίας', 'topon apologias', 'G5117/G627', 'Place of defence — opportunity to answer.', 18),
  (19, 'δεισιδαιμονίας', 'deisidaimonias', 'G1175', 'Superstition/religion — Festus''s neutral-pejorative term.', 19),
  (19, 'Ἰησοῦ τεθνηκότος... ζῆν', 'Iēsou tethnēkotos... zēn', 'G2424/G2348/G2198', 'Jesus dead... alive — Paul''s resurrection claim.', 20),
  (20, 'ἀπορούμενος', 'aporoumenos', 'G639', 'Being perplexed — Festus''s feigned perplexity.', 21),
  (21, 'Σεβαστοῦ', 'Sebastou', 'G4575', 'Augustus — "the venerable," imperial title (Nero).', 22),
  (21, 'διάγνωσιν', 'diagnōsin', 'G1233', 'Judicial determination, diagnosis.', 23),
  (23, 'φαντασίας', 'phantasias', 'G5325', 'Pomp, ostentation — royal display.', 24),
  (23, 'ἀκροατήριον', 'akroatērion', 'G201', 'Audience hall — place of formal hearing.', 25),
  (24, 'ἐπιβοῶντες', 'epiboōntes', 'G1916', 'Crying out against — angry clamour.', 26),
  (25, 'ἄξιον θανάτου', 'axion thanatou', 'G514/G2288', 'Worthy of death — Roman verdict of innocence.', 27),
  (26, 'τῷ Κυρίῳ', 'tō Kyriō', 'G2962', 'To the lord — here Nero; Christians will not use this of him.', 28),
  (26, 'ἀνακρίσεως', 'anakriseōs', 'G351', 'Examination, preliminary hearing.', 29),
  (27, 'ἄλογον', 'alogon', 'G249', 'Irrational, without reason — Festus''s self-indictment.', 30)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 25 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

